struct DSU {
    parent: Vec<usize>,
    rank: Vec<usize>,
    components: usize,
}

impl DSU {
    fn new(n: usize) -> Self {
        DSU {
            parent: (0..n).collect(),
            rank: vec![0; n],
            components: n,
        }
    }

    fn find(&mut self, x: usize) -> usize {
        if self.parent[x] != x {
            self.parent[x] = self.find(self.parent[x]);
        }
        self.parent[x]
    }

    fn union(&mut self, x: usize, y: usize) -> bool {
        let mut x_root = self.find(x);
        let mut y_root = self.find(y);
        if x_root == y_root {
            return false;
        }
        if self.rank[x_root] < self.rank[y_root] {
            std::mem::swap(&mut x_root, &mut y_root);
        }
        self.parent[y_root] = x_root;
        if self.rank[x_root] == self.rank[y_root] {
            self.rank[x_root] += 1;
        }
        self.components -= 1;
        true
    }
}

fn feasible(x: i64, n: i64, edges: &Vec<Vec<i64>>, k: i64) -> bool {
    let n = n as usize;
    let mut dsu = DSU::new(n);

    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let s = edge[2];
        let must = edge[3];
        if must == 1 && s < x {
            return false;
        }
    }

    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let s = edge[2];
        let must = edge[3];
        if must == 1 {
            if !dsu.union(u, v) {
                return false;
            }
        }
    }

    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let s = edge[2];
        let must = edge[3];
        if must == 0 && s >= x {
            dsu.union(u, v);
        }
    }

    let mut upgrade_count = 0;
    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let s = edge[2];
        let must = edge[3];
        if must == 0 && s < x && 2 * s >= x {
            if dsu.union(u, v) {
                upgrade_count += 1;
            }
        }
    }

    if dsu.components != 1 {
        return false;
    }
    if upgrade_count as i64 > k {
        return false;
    }
    true
}

fn solve(n: i64, edges: Vec<Vec<i64>>, k: i64) -> i64 {
    if edges.is_empty() {
        if n == 1 {
            return 0;
        } else {
            return -1;
        }
    }
    let max_s = edges.iter().map(|v| v[2]).max().unwrap();
    let high_bound = max_s * 2;
    let mut low = 0;
    let mut high = high_bound;
    let mut ans = -1;

    while low <= high {
        let mid = low + (high - low) / 2;
        if feasible(mid, n, &edges, k) {
            ans = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }
    ans
}
